sql:
SELECT DISTINCT c.first_name, c.last_name, c.email
FROM customers c
JOIN claims cl ON c.customer_id = cl.customer_id;

SELECT customers.first_name, customers.last_name 
FROM customers 
INNER JOIN claims ON claims.customer_id = customers.customer_id;

SELECT policy_id, SUM(sales_amount) AS total_sales
FROM policy_sales_data
GROUP BY policy_id;

SELECT DISTINCT customers.customer_id, customers.first_name, customers.last_name
FROM customers
INNER JOIN policies ON customers.customer_id = policies.customer_id;
